#include <stdio.h>
#include <stdlib.h>

int min_stops(int* a, int N, int M) {
    int** dp = (int**)malloc(N * sizeof(int*));
    int** ways = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        dp[i] = (int*)malloc(N * sizeof(int));
        ways[i] = (int*)malloc(N * sizeof(int));
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            dp[i][j] = -1;
            ways[i][j] = 0;
        }
    }
    for (int i = 0; i < N; i++) {
        for (int j = i; j < N; j++) {
            if (j == i) {
                dp[i][j] = 0;
                ways[i][j] = 1;
            } else if (a[j] - a[i] <= M) {
                dp[i][j] = 0;
                ways[i][j] = 1;
            } else {
                int min = 1000000;
                int way = 0;
                for (int k = i + 1; k < j; k++) {
                    if (dp[i][k] != -1 && dp[k][j] != -1 && dp[i][k] + dp[k][j] + 1 < min) {
                        min = dp[i][k] + dp[k][j] + 1;
                        way = ways[i][k] * ways[k][j];
                    }
                }
                dp[i][j] = min;
                ways[i][j] = way;
            }
        }
    }
    int min = dp[0][N - 1];
    int way = ways[0][N - 1];
    for (int i = 0; i < N; i++) {
        free(dp[i]);
        free(ways[i]);
    }
    free(dp);
    free(ways);
    printf("%d %d\n", min, way);
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int* a = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &a[i]);
        }
        min_stops(a, N, M);
        free(a);
    }
    return 0;
}

